     [Description("Searches the web for information about a query and returns relevant results with titles, snippets, and URLs.")]
     public async Task<string> SearchWeb(
         [Description("The search query to look up on the web")] string query)
     {
         try
         {
             var encoded = WebUtility.UrlEncode(query);
             var url = $"https://html.duckduckgo.com/html/?q={encoded}";

             using var request = new HttpRequestMessage(HttpMethod.Get, url);
             request.Headers.UserAgent.ParseAdd("ResearchAgent/1.0");

             using var response = await _httpClient.GetAsync(url);
             response.EnsureSuccessStatusCode();

             var html = await response.Content.ReadAsStringAsync();

             var results = ParseSearchResults(html);
             if (results.Count == 0)
             {
                 return $"No results found for: {query}";
             }

             return $"Search results for \"{query}\":\n\n" +
                    string.Join("\n\n", results.Take(5));
         }
         catch (Exception ex)
         {
             return $"Search failed for \"{query}\": {ex.Message}";
         }
     }

     /// <summary>
     /// Saves a research note for later reference.
     /// </summary>
     [Description("Saves a research note with a source attribution. Use this to record important findings during research.")]
     public string SaveNote(
         [Description("The content of the note to save")] string content,
         [Description("The source URL or description where this information was found")] string source)
     {
         var note = $"[{_notes.Count + 1}] {content} (Source: {source})";
         _notes.Add(note);
         return $"Note saved successfully (#{_notes.Count}).";
     }

     /// <summary>
     /// Retrieves all saved research notes.
     /// </summary>
     [Description("Retrieves all saved research notes from the current session. Call this before writing a summary.")]
     public string GetNotes()
     {
         if (_notes.Count == 0)
         {
             return "No notes saved yet.";
         }

         return $"Saved notes ({_notes.Count} total):\n\n" +
                string.Join("\n", _notes);
     }

     private static List<string> ParseSearchResults(string html)
     {
         var results = new List<string>();

         // Parse DuckDuckGo HTML result entries
         var resultBlocks = html.Split("class=\"result__body", StringSplitOptions.RemoveEmptyEntries);

         foreach (var block in resultBlocks.Skip(1).Take(5))
         {
             var title = ExtractBetween(block, "class=\"result__a\"", "</a>");
             var snippet = ExtractBetween(block, "class=\"result__snippet", "</a>");
             var url = ExtractHref(block, "class=\"result__url\"");

             if (title is null && snippet is null)
             {
                 continue;
             }

             title = StripHtml(title ?? "No title");
             snippet = StripHtml(snippet ?? "No snippet");
             url = StripHtml(url ?? "No URL").Trim();

             results.Add($"Title: {title}\nURL: {url}\nSnippet: {snippet}");
         }

         return results;
     }

     private static string? ExtractBetween(string text, string startMarker, string endMarker)
     {
         var startIdx = text.IndexOf(startMarker, StringComparison.OrdinalIgnoreCase);
         if (startIdx < 0)
         {
             return null;
         }

         var closeTag = text.IndexOf('>', startIdx + startMarker.Length);
         if (closeTag < 0)
         {
             return null;
         }

         var contentStart = closeTag + 1;
         var endIdx = text.IndexOf(endMarker, contentStart, StringComparison.OrdinalIgnoreCase);
         if (endIdx < 0)
         {
             return null;
         }

         return text[contentStart..endIdx];
     }

     private static string? ExtractHref(string text, string marker)
     {
         var idx = text.IndexOf(marker, StringComparison.OrdinalIgnoreCase);
         if (idx < 0)
         {
             return null;
         }

         var hrefIdx = text.IndexOf("href=\"", idx, StringComparison.OrdinalIgnoreCase);
         if (hrefIdx < 0)
         {
             return null;
         }

         var start = hrefIdx + 6;
         var end = text.IndexOf('"', start);
         return end < 0 ? null : text[start..end];
     }

     private static string StripHtml(string html)
     {
         // Remove HTML tags and decode common entities
         var text = System.Text.RegularExpressions.Regex.Replace(html, "<[^>]+>", "");
         return WebUtility.HtmlDecode(text).Trim();
     }
